  ('heelevel3-bd9337dc-moex-00009', 'heelevel3-bd9337dc', 'heelevel3-bd9337dc-moex-114-3082b5f1', 'sub-heelevel3-bd9337dc-03', NULL, 'essay', '甲財團法人為辦理友善新住民活動，向 A市政府社會局申請補助新臺幣
（下同）二十萬元，A市政府檢核相關申請文件後，以 B函通知甲財團
法人通過補助，核發第一期補助款十萬元，並請甲財團法人舉辦活動後，
檢附相關支出憑證以辦理核銷，並於三個月後檢具第一期成果報告書，
經審查通過後再申請支付第二期補助款。不料甲財團法人檢具之支出憑
證不但未齊全，成果報告書之資料經查多處偽造不實，試問：A市政府
社會局應如何向甲財團法人要求返還已經支付之補助款十萬元，並不支
付第二期補助款？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:22+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "209", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公職社會工作師"}'::jsonb, NULL),
